export function AttributeFrom(AttributeName, Attributes) {
    for (let i = 0, l = Attributes.length; i < l; i++) {
        let Attribute = Attributes[i];
        if (Attribute.Name === AttributeName) {
            return Attribute.Value;
        }
    }
    return undefined;
}
